// graphql/queries/employeeQueries.js

export const GET_EMPLOYEES = `
  query GetEmployees {
    employees {
      id
      email
      first_name
      last_name
      phone
      status
      employee_code
      gender
      created_at
      updated_at
      department {
        id
        name
      }
    }
  }
`;

export const GET_EMPLOYEE_BY_ID = `
  query GetEmployeeById($id: Int!) {
    employees_by_pk(id: $id) {
      id
      email
      first_name
      last_name
      phone
      status
      employee_code
      gender
      level_id
      role_id
      department_id
      created_at
      updated_at
      level {
        id
        name
      }
      role {
        id
        name
      }
      department {
        id
        name
      }
    }
  }
`;